export const orthoGetGroup = c => {
  if (c.includes("Bracket")) return "Brackets";
  if (c.includes("Bonding") || c.includes("Adhesive") || c.includes("Etching")) return "Bonding";
  if (c.includes("Wire") || c.includes("Archwire")) return "Archwires";
  if (c.includes("IPR") || c.includes("Interproximal")) return "Interproximal Reduction";
  if (c.includes("Retention") || c.includes("Retainer")) return "Retention";
  if (c.includes("Aligner")) return "Clear Aligners";
  if (c.includes("Fiberotomy") || c.includes("CSF") || c.includes("Piezocision") || c.includes("Surgical Adjunct")) return "Surgical Adjuncts";
  if (c.includes("TAD") || c.includes("Anchorage") || c.includes("Miniscrew")) return "Temporary Anchorage Devices";
  if (c.includes("Space Analysis") || c.includes("Protocol") || c.includes("Scope")) return "Protocols & Space Analysis";
  return "Other";
};

export const ORTHO_GROUPS = ["Brackets", "Bonding", "Archwires", "Interproximal Reduction", "Retention", "Clear Aligners", "Surgical Adjuncts", "Temporary Anchorage Devices", "Protocols & Space Analysis"];

